import axios from "./axios";

export const addAppointment = async (data) => {
  const token = localStorage.getItem("token"); // get token after login

  return axios.post("/appointments/add", data, {
    headers: {
      Authorization: `Bearer ${token}`,  // 🔑 send token
    },
  });
};

export const getAppointments = () => axios.get("/appointments");

export const getAppointmentsByStatus = (status) => axios.get(`/appointments?status=${status}`);
